import * as THREE from 'three';

type ViewMode = 'front' | 'side' | 'top' | 'perspective' | 'section';
type MaterialMode = 'normal' | 'silhouette' | 'wireframe';

type Point = {
  x: number;
  y: number;
};

const canvas = document.querySelector<HTMLCanvasElement>('#palmate-canvas');
if (!canvas) throw new Error('Palmate 3D Mini Lab canvas is missing.');
const canvasElement = canvas;

const infoPanel = document.querySelector<HTMLElement>('#info');
const params = new URLSearchParams(window.location.search);
const requestedView = params.get('view');
const view: ViewMode =
  requestedView === 'front' || requestedView === 'side' || requestedView === 'top' || requestedView === 'perspective' || requestedView === 'section'
    ? requestedView
    : 'perspective';
const requestedMode = params.get('mode');
const mode: MaterialMode = requestedMode === 'normal' || requestedMode === 'silhouette' || requestedMode === 'wireframe' ? requestedMode : 'normal';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x10160f);

const camera = new THREE.PerspectiveCamera(34, 1, 0.1, 80);
let renderer: THREE.WebGLRenderer;
try {
  renderer = new THREE.WebGLRenderer({ canvas: canvasElement, antialias: true, alpha: false, powerPreference: 'high-performance' });
} catch (error) {
  if (infoPanel) {
    infoPanel.textContent = [
      'Palmate 3D Mini Lab',
      'WebGL context failed in this browser/runtime.',
      'The source is valid, but this environment disabled WebGL.',
      error instanceof Error ? error.message : String(error)
    ].join('\n');
  }
  throw error;
}
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.outputColorSpace = THREE.SRGBColorSpace;

const leafMaterial = new THREE.MeshStandardMaterial({
  color: mode === 'silhouette' ? 0x020402 : 0x4b7334,
  roughness: 0.82,
  metalness: 0.01,
  side: THREE.DoubleSide
});
const petioleMaterial = new THREE.MeshStandardMaterial({
  color: mode === 'silhouette' ? 0x020402 : 0x385927,
  roughness: 0.86,
  metalness: 0
});
const sectionMaterial = new THREE.MeshStandardMaterial({
  color: mode === 'silhouette' ? 0x020402 : 0x9dc078,
  roughness: 0.76,
  metalness: 0,
  side: THREE.DoubleSide
});

if (mode === 'wireframe') {
  leafMaterial.wireframe = true;
  petioleMaterial.wireframe = true;
  sectionMaterial.wireframe = true;
}

scene.add(new THREE.HemisphereLight(0xe8f6dc, 0x172210, mode === 'silhouette' ? 1.3 : 1.75));
const keyLight = new THREE.DirectionalLight(0xffffff, mode === 'silhouette' ? 0.25 : 2.35);
keyLight.position.set(5, 7, 7);
scene.add(keyLight);
const rimLight = new THREE.DirectionalLight(0xb8dc9e, mode === 'silhouette' ? 0.15 : 0.65);
rimLight.position.set(-6, 4, -6);
scene.add(rimLight);

const root = new THREE.Group();
scene.add(root);

// Same T1 traced silhouette family as Leaf Silhouette Lab, mapped to local +Y apex space.
const t1TracePixels: readonly Point[] = [
  { x: 0, y: 86 },
  { x: 18, y: 84 },
  { x: 38, y: 74 },
  { x: 82, y: 62 },
  { x: 154, y: 34 },
  { x: 132, y: 24 },
  { x: 108, y: 6 },
  { x: 118, y: -34 },
  { x: 152, y: -86 },
  { x: 110, y: -82 },
  { x: 72, y: -86 },
  { x: 52, y: -122 },
  { x: 0, y: -170 },
  { x: -52, y: -122 },
  { x: -72, y: -86 },
  { x: -110, y: -82 },
  { x: -152, y: -86 },
  { x: -118, y: -34 },
  { x: -108, y: 6 },
  { x: -132, y: 24 },
  { x: -154, y: 34 },
  { x: -82, y: 62 },
  { x: -38, y: 74 },
  { x: -18, y: 84 }
];

const traceScale = 1 / 48;
function sampleClosedCatmull(points: readonly Point[], samplesPerSegment = 5) {
  const sampled: THREE.Vector2[] = [];
  const count = points.length;
  for (let index = 0; index < count; index += 1) {
    const p0 = points[(index - 1 + count) % count];
    const p1 = points[index];
    const p2 = points[(index + 1) % count];
    const p3 = points[(index + 2) % count];
    for (let sample = 0; sample < samplesPerSegment; sample += 1) {
      const t = sample / samplesPerSegment;
      const t2 = t * t;
      const t3 = t2 * t;
      const x =
        0.5 *
        (2 * p1.x +
          (-p0.x + p2.x) * t +
          (2 * p0.x - 5 * p1.x + 4 * p2.x - p3.x) * t2 +
          (-p0.x + 3 * p1.x - 3 * p2.x + p3.x) * t3);
      const y =
        0.5 *
        (2 * p1.y +
          (-p0.y + p2.y) * t +
          (2 * p0.y - 5 * p1.y + 4 * p2.y - p3.y) * t2 +
          (-p0.y + 3 * p1.y - 3 * p2.y + p3.y) * t3);
      sampled.push(new THREE.Vector2(x * traceScale, -y * traceScale));
    }
  }
  return sampled;
}

const contour = sampleClosedCatmull(t1TracePixels);
const petioleInsertion = new THREE.Vector2(0, -86 * traceScale);
const palmCentre = new THREE.Vector2(0, -8 * traceScale);
const primaryTargets = [
  new THREE.Vector2(0, 170 * traceScale),
  new THREE.Vector2(152 * traceScale, 86 * traceScale),
  new THREE.Vector2(-152 * traceScale, 86 * traceScale),
  new THREE.Vector2(154 * traceScale, -34 * traceScale),
  new THREE.Vector2(-154 * traceScale, -34 * traceScale)
];

function clamp01(value: number) {
  return Math.max(0, Math.min(1, value));
}

function smoothstep(edge0: number, edge1: number, value: number) {
  const t = clamp01((value - edge0) / (edge1 - edge0));
  return t * t * (3 - 2 * t);
}

function mix(a: number, b: number, t: number) {
  return a + (b - a) * t;
}

function distanceToSegment(point: THREE.Vector2, start: THREE.Vector2, end: THREE.Vector2) {
  const segment = new THREE.Vector2().subVectors(end, start);
  const lengthSq = segment.lengthSq();
  if (lengthSq === 0) return point.distanceTo(start);
  const t = clamp01(new THREE.Vector2().subVectors(point, start).dot(segment) / lengthSq);
  const projected = start.clone().add(segment.multiplyScalar(t));
  return point.distanceTo(projected);
}

function primaryReliefAt(point: THREE.Vector2) {
  return primaryTargets.reduce((sum, target) => {
    const distance = distanceToSegment(point, petioleInsertion, target);
    return sum + Math.exp(-(distance * distance) / 0.012);
  }, 0);
}

function makeSurfaceVertex(point: THREE.Vector2, radial: number, side: 'top' | 'bottom') {
  const bounds = { minY: -1.9, maxY: 3.55, maxX: 3.25 };
  const yT = clamp01((point.y - bounds.minY) / (bounds.maxY - bounds.minY));
  const xT = clamp01(Math.abs(point.x) / bounds.maxX);
  const longitudinalArch = Math.sin(yT * Math.PI) * 0.1 - Math.pow(1 - yT, 2.2) * 0.035;
  const transverseCup = Math.pow(xT, 1.9) * 0.075;
  const lobeTipLift = smoothstep(0.7, 1, radial) * Math.sin((point.x + point.y) * 1.7) * 0.018;
  const relief = primaryReliefAt(point) * (0.008 + 0.008 * smoothstep(0.2, 0.88, radial));
  const midSurface = longitudinalArch + transverseCup + lobeTipLift;
  const thickness = mix(0.044, 0.007, smoothstep(0.74, 1, radial));
  return side === 'top' ? midSurface - relief : midSurface - thickness + relief * 1.25;
}

function createPalmateLeafGeometry() {
  const radialSegments = 16;
  const boundaryCount = contour.length;
  const positions: number[] = [];
  const indices: number[] = [];

  for (const side of ['top', 'bottom'] as const) {
    for (let radialIndex = 0; radialIndex <= radialSegments; radialIndex += 1) {
      const radial = radialIndex / radialSegments;
      for (let boundaryIndex = 0; boundaryIndex < boundaryCount; boundaryIndex += 1) {
        const boundary = contour[boundaryIndex];
        const point = palmCentre.clone().lerp(boundary, radial);
        positions.push(point.x, point.y, makeSurfaceVertex(point, radial, side));
      }
    }
  }

  const sideOffset = (side: number) => side * (radialSegments + 1) * boundaryCount;
  const indexAt = (side: number, radialIndex: number, boundaryIndex: number) =>
    sideOffset(side) + radialIndex * boundaryCount + ((boundaryIndex + boundaryCount) % boundaryCount);

  for (let side = 0; side < 2; side += 1) {
    for (let radialIndex = 0; radialIndex < radialSegments; radialIndex += 1) {
      for (let boundaryIndex = 0; boundaryIndex < boundaryCount; boundaryIndex += 1) {
        const nextBoundary = boundaryIndex + 1;
        const a = indexAt(side, radialIndex, boundaryIndex);
        const b = indexAt(side, radialIndex + 1, boundaryIndex);
        const c = indexAt(side, radialIndex + 1, nextBoundary);
        const d = indexAt(side, radialIndex, nextBoundary);
        if (side === 0) indices.push(a, b, d, b, c, d);
        else indices.push(a, d, b, b, d, c);
      }
    }
  }

  for (let boundaryIndex = 0; boundaryIndex < boundaryCount; boundaryIndex += 1) {
    const nextBoundary = boundaryIndex + 1;
    const topA = indexAt(0, radialSegments, boundaryIndex);
    const topB = indexAt(0, radialSegments, nextBoundary);
    const bottomA = indexAt(1, radialSegments, boundaryIndex);
    const bottomB = indexAt(1, radialSegments, nextBoundary);
    indices.push(topA, topB, bottomA, topB, bottomB, bottomA);
  }

  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setIndex(indices);
  geometry.computeVertexNormals();
  geometry.computeBoundingBox();
  geometry.computeBoundingSphere();
  return geometry;
}

function createCylinderBetween(start: THREE.Vector3, end: THREE.Vector3, radiusStart: number, radiusEnd: number, material: THREE.Material) {
  const direction = new THREE.Vector3().subVectors(end, start);
  const length = direction.length();
  const geometry = new THREE.CylinderGeometry(radiusEnd, radiusStart, length, 14, 1, false);
  const mesh = new THREE.Mesh(geometry, material);
  mesh.position.copy(start).addScaledVector(direction, 0.5);
  mesh.quaternion.setFromUnitVectors(new THREE.Vector3(0, 1, 0), direction.normalize());
  return mesh;
}

function createSectionSample() {
  const widthSegments = 24;
  const width = 3.4;
  const positions: number[] = [];
  const indices: number[] = [];

  for (let side = 0; side < 2; side += 1) {
    for (let index = 0; index <= widthSegments; index += 1) {
      const u = index / widthSegments;
      const signed = u * 2 - 1;
      const edge = Math.abs(signed);
      const x = signed * width * 0.5;
      const cup = Math.pow(edge, 1.8) * 0.05;
      const thickness = mix(0.052, 0.006, smoothstep(0.72, 1, edge));
      const relief = Math.exp(-(x * x) / 0.12) * 0.012;
      const z = (side === 0 ? cup - relief : cup - thickness + relief) * 8;
      positions.push(x, -2.55, z);
    }
  }

  const row = widthSegments + 1;
  for (let index = 0; index < widthSegments; index += 1) {
    const a = index;
    const b = index + 1;
    const c = row + index;
    const d = row + index + 1;
    indices.push(a, c, b, b, c, d);
  }

  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setIndex(indices);
  geometry.computeVertexNormals();

  const mesh = new THREE.Mesh(geometry, sectionMaterial);
  mesh.name = 'section-thickness-sample';
  mesh.visible = view === 'section';
  return mesh;
}

const leaf = new THREE.Mesh(createPalmateLeafGeometry(), leafMaterial);
leaf.name = 'T1 traced palmate blade';
root.add(leaf);

const petioleStart = new THREE.Vector3(0, petioleInsertion.y - 0.9, -0.012);
const petioleEnd = new THREE.Vector3(petioleInsertion.x, petioleInsertion.y + 0.04, -0.006);
const petiole = createCylinderBetween(petioleStart, petioleEnd, 0.035, 0.026, petioleMaterial);
petiole.name = 'short petiole';
root.add(petiole);

const sectionSample = createSectionSample();
root.add(sectionSample);

const width = 6.42;
const height = 5.33;
const petioleLength = petioleStart.distanceTo(petioleEnd);
const thicknessRange = '0.006-0.052';

function setCamera(nextView: ViewMode) {
  const target = new THREE.Vector3(0, 0.45, 0);
  camera.fov = nextView === 'section' ? 16 : 34;
  if (nextView === 'front') camera.position.set(0, 0.45, 14);
  if (nextView === 'side') camera.position.set(8, 0.35, 0.65);
  if (nextView === 'top') camera.position.set(0, 8.4, 0.72);
  if (nextView === 'perspective') camera.position.set(5.4, 2.3, 10.6);
  if (nextView === 'section') {
    camera.position.set(0, -6.9, 0.32);
    target.set(0, -2.55, -0.01);
  }
  if (nextView === 'top' || nextView === 'section') camera.up.set(0, 0, 1);
  else camera.up.set(0, 1, 0);
  camera.lookAt(target);
  camera.updateProjectionMatrix();
}

function updateButtons() {
  document.querySelectorAll<HTMLButtonElement>('[data-view]').forEach((button) => {
    button.setAttribute('aria-pressed', String(button.dataset.view === view));
  });
  document.querySelectorAll<HTMLButtonElement>('[data-mode]').forEach((button) => {
    button.setAttribute('aria-pressed', String(button.dataset.mode === mode));
  });
}

function updateInfo() {
  if (!infoPanel) return;
  infoPanel.textContent = [
    'Palmate 3D Mini Lab',
    'baseline: T1 traced silhouette',
    `view / mode: ${view} / ${mode}`,
    `blade width / height: ${width.toFixed(2)} / ${height.toFixed(2)}`,
    `petiole length: ${petioleLength.toFixed(2)}`,
    `thickness range: ${thicknessRange}`,
    'hasPrimaryRelief: yes, extremely shallow',
    'venation relief: 5 primary palmate rays only',
    'surfaceForm: slight longitudinal arch / slight transverse cup',
    view === 'section' ? 'section display: isolated slice, vertical relief magnified for inspection' : 'section display: available via section view',
    "prototypeStatus: '3d-mini-lab-not-system-integrated'"
  ].join('\n');
}

function resize() {
  const rect = canvasElement.getBoundingClientRect();
  renderer.setSize(rect.width, rect.height, false);
  camera.aspect = rect.width / rect.height;
  camera.updateProjectionMatrix();
  renderer.render(scene, camera);
}

function navigate(nextParams: Record<string, string>) {
  const next = new URLSearchParams(window.location.search);
  Object.entries(nextParams).forEach(([key, value]) => next.set(key, value));
  window.location.href = `${window.location.pathname}?${next.toString()}`;
}

document.querySelectorAll<HTMLButtonElement>('[data-view]').forEach((button) => {
  button.addEventListener('click', () => {
    const nextView = button.dataset.view;
    if (nextView) navigate({ view: nextView });
  });
});

document.querySelectorAll<HTMLButtonElement>('[data-mode]').forEach((button) => {
  button.addEventListener('click', () => {
    const nextMode = button.dataset.mode;
    if (nextMode) navigate({ mode: nextMode });
  });
});

setCamera(view);
updateButtons();
updateInfo();
window.addEventListener('resize', resize);
resize();
